    if isinstance(item, dict):
        raw = item.get("freshness")
        if raw is not None:
            try:
                return Freshness(raw)
            except ValueError:
                return None
    f = getattr(item, "freshness", None)
    if isinstance(f, Freshness):
        return f
    if isinstance(f, str):
        try:
            return Freshness(f)
        except ValueError:
            return None
    return None

